void _likeUser(UserCard user) async {
  final existing = _likedIds.contains(user.id);
  if (existing) {
    setState(() => _likedIds.remove(user.id));
    return;
  }

  setState(() => _likedIds.add(user.id));

  // Show recording popup with "Like Without VM" option
  final voicePath = await showModalBottomSheet<String?>(
    context: context,
    isScrollControlled: true,
    backgroundColor: Colors.transparent,
    builder: (ctx) => VoiceNoteRecorder(username: user.username),
  );

  // Whether they recorded or chose "Like Without VM", go to WIL
  if (mounted) {
    if (widget.wilRefreshTick != null) {
      widget.wilRefreshTick!.value++;
    }
    if (widget.onSwitchTab != null) {
      widget.onSwitchTab!(1); // Switch to WIL tab
    } else {
      Navigator.of(context).pushReplacementNamed('/who-i-like');
    }
  }
}

void _blockUser(int userId) {
  setState(() => _blockedIds.add(userId));
  ScaffoldMessenger.of(context).showSnackBar(
    const SnackBar(content: Text('User blocked')),
  );
}

