}

Future<void> _togglePlay(int userId) async {
  if (_playing[userId] == true) {
    await _audioPlayer.stop();
    setState(() => _playing[userId] = false);
    return;
  }

  try {
    final voiceUrl = '${widget.baseUrl}/api/like/$userId/voice';
    await _audioPlayer.play(UrlSource(voiceUrl));
    setState(() {
      for (final k in _playing.keys.toList()) _playing[k] = false;
      _playing[userId] = true;
    });
  } catch (_) {}
}

