return Column(
  children: [
    Expanded(
      child: ReorderableListView.builder(
        padding: const EdgeInsets.only(top: 8, bottom: 80),
        itemCount: _likes.length,
        onReorder: (oldIndex, newIndex) {
          // Prevent moving rank #1 (position 0) - ALWAYS immovable
          // Also prevent other items from being moved into position 0
          if (oldIndex == 0 || newIndex == 0) {
            return;
          }

          setState(() {
            if (newIndex > oldIndex) newIndex--;
            final item = _likes.removeAt(oldIndex);
            _likes.insert(newIndex, item);
          });
          _pushRerank();
        },
        itemBuilder: (context, index) {
          final user = _likes[index];
          final rank = index + 1;
          final int userId = user['id'] as int? ?? 0;
          final String username = user['username'] as String? ?? '';
          final int? age = user['age'] as int?;
          final String? sex = user['sex'] as String?;
          final String photoUrl = '$_baseUrl/api/users/$userId/photo';
          final String? voiceUrl = user['voice_note_url'] as String?;
          final bool isLocked = rank == 1 && _activeRankOne != null;
          // timerExpires removed for cleaner manual mode

          return Slidable(
            key: ValueKey(userId),
            enabled: !isLocked, // Disable swipe for locked rank #1
            endActionPane: ActionPane(
              motion: const BehindMotion(),
              extentRatio: 0.25,
              children: [
                SlidableAction(
                  onPressed: (_) => _unlikeUser(userId),
                  backgroundColor: Colors.redAccent,
                  foregroundColor: Colors.white,
                  icon: Icons.delete_outline,
                  label: 'Unlike',
                  borderRadius: BorderRadius.circular(8),
                ),
              ],
            ),
            child: _WhoILikeTile(

      height: 32,
      decoration: BoxDecoration(color: Colors.black.withOpacity(0.65), shape: BoxShape.circle),
      child: const Icon(Icons.close, color: Colors.white, size: 18),
    ),
  ),
),

// Like button
Positioned(
  right: 6,
  bottom: 6,
  child: GestureDetector(
    onTap: () => _likeUser(user),
    child: Container(
      width: 32,
