Future<void> _likeUser() async {
  if (_liked) {
    ScaffoldMessenger.of(context).showSnackBar(
      const SnackBar(content: Text('Already liked')),
    );
    return;
  }

  // Optimistic UI — filled heart is the only non-match feedback.
  setState(() => _liked = true);

  try {
    final resp = await http.post(
      Uri.parse('$_baseUrl/api/like'),
      headers: _headers,
      body: jsonEncode({'liked_user_id': widget.userId}),
    );

    if (resp.statusCode == 200 || resp.statusCode == 201) {
      final body = jsonDecode(resp.body) as Map<String, dynamic>;
      final status = body['status'] as String?;

      if (status == 'matched') {
        // Defensive: filtering should prevent this in normal flow, but
        // handle gracefully if a user-who-liked-me slips through.
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text("🎉 It's a match!")),
          );
          Navigator.of(context).pop();
        }
      }
      // Non-match: stay on profile, filled heart speaks for itself.
    } else {
      setState(() => _liked = false);
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Like failed (${resp.statusCode})')),
        );
      }
    }
  } catch (e) {
    setState(() => _liked = false);
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Like error: $e')),
      );
    }
  }
}

