Future<void> _likeUser(UserCard user) async {
  // Red heart is a no-op on Discover — unlike lives on WIL only.
  if (_likedIds.contains(user.id)) return;

  // Optimistic UI
  setState(() => _likedIds.add(user.id));

  try {
    final resp = await http.post(
      Uri.parse('$_baseUrl/api/like'),
      headers: {
        'Content-Type': 'application/json',
        if (_token != null) 'Authorization': 'Bearer $_token',
      },
      body: jsonEncode({'liked_user_id': user.id}),
    );

    if (resp.statusCode == 200 || resp.statusCode == 201) {
      final body = jsonDecode(resp.body) as Map<String, dynamic>;
      final status = body['status'] as String?;

      if (status == 'matched') {
        // Defensive: filtering should stop this reaching Discover, but
        // handle it gracefully if a user-who-liked-me slips through.
        setState(() => _users.removeWhere((u) => u.id == user.id));
        if (mounted) {
          ScaffoldMessenger.of(context).showSnackBar(
            const SnackBar(content: Text("🎉 It's a match!")),
          );
        }
        return;
      }

      // Normal like: bump WIL + switch tab.
      if (mounted) {
        widget.wilRefreshTick?.value++;
        if (widget.onSwitchTab != null) {
          widget.onSwitchTab!(1);
        } else {
          Navigator.of(context).pushReplacementNamed('/who-i-like');
        }
      }
    } else {
      setState(() => _likedIds.remove(user.id));
      if (mounted) {
        ScaffoldMessenger.of(context).showSnackBar(
          SnackBar(content: Text('Like failed (${resp.statusCode})')),
        );
      }
    }
  } catch (e) {
    setState(() => _likedIds.remove(user.id));
    if (mounted) {
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Like error: $e')),
      );
    }
  }
}

